// src/components/Navbar.jsx
import React from "react";
import { AppBar, Toolbar, Typography, Button, Box } from "@mui/material";
import { Link, useLocation } from "react-router-dom";
import LocalHospitalIcon from "@mui/icons-material/LocalHospital";

const Navbar = () => {
  const location = useLocation();
  const isAdmin = location.pathname.startsWith("/admin");

  return (
    <AppBar position="sticky" sx={{ bgcolor: "#1976d2", boxShadow: 3 }}>
      <Toolbar>
        <Box
          sx={{ display: "flex", alignItems: "center", gap: 1.5, flexGrow: 1 }}
        >
          <LocalHospitalIcon sx={{ fontSize: 32 }} />
          <Typography
            variant="h6"
            component={Link}
            to="/"
            sx={{ color: "white", textDecoration: "none", fontWeight: 700 }}
          >
            Arogya Nepal
          </Typography>
        </Box>

        {!isAdmin && (
          <>
            <Button color="inherit" component={Link} to="/">
              Hospitals
            </Button>
            <Button color="inherit" component={Link} to="/my-appointments">
              My Appointments
            </Button>
          </>
        )}

        <Button
          color="inherit"
          variant="outlined"
          sx={{ ml: 2, borderColor: "white", color: "white" }}
          component={Link}
          to={isAdmin ? "/" : "/admin/dashboard"}
        >
          {isAdmin ? "Patient View" : "Admin Dashboard"}
        </Button>
      </Toolbar>
    </AppBar>
  );
};

export default Navbar;
